                    <option value="Debito"${ei.tipoMovimento === 'Debito' ? ' selected' : ''}>Débito</option>
                    <option value="Credito"${ei.tipoMovimento === 'Credito' ? ' selected' : ''}>Crédito</option>
                    <option value="Dinheiro"${ei.tipoMovimento === 'Dinheiro' ? ' selected' : ''}>Dinheiro</option>
                    <option value="Pix"${ei.tipoMovimento === 'Pix' ? ' selected' : ''}>Pix</option>
                    <option value="Boleto"${ei.tipoMovimento === 'Boleto' ? ' selected' : ''}>Boleto</option>
                    <option value="Voucher"${ei.tipoMovimento === 'Voucher' ? ' selected' : ''}>Voucher</option>
                </select>
                <label for="erMovimento">Movimento</label>
                <span style="position:absolute;right:14px;top:50%;transform:translateY(-50%);color:var(--cor-principal);pointer-events:none;">▾</span>
            </div>

            <div id="erWrapParcelas" class="er-field-wrap" style="${mostrarParcelas ? '' : 'display:none;'}">
                <input id="erParcelas" type="number" min="1" placeholder=" " value="${ei.parcelas || 1}">
                <label for="erParcelas">Parcelas</label>
            </div>

            <!-- Multi-select: Instituições -->
            <div style="display:flex;flex-direction:column;gap:6px;">
                <span style="font-size:0.82rem;font-weight:700;color:var(--cor-texto-secundario);text-transform:uppercase;letter-spacing:0.5px;">
                    Instituições <span style="font-weight:400;text-transform:none;">(selecione uma ou mais)</span>
                </span>
                <div style="border:1px solid var(--cor-tinte-borda);border-radius:10px;padding:8px 10px;max-height:130px;overflow-y:auto;
                            background:var(--cor-fundo-campo,var(--cor-fundo-card));display:flex;flex-direction:column;gap:2px;">
                    ${instChecksHtml}
                </div>
            </div>

            <!-- Multi-select: Categorias -->
            <div style="display:flex;flex-direction:column;gap:6px;">
                <span style="font-size:0.82rem;font-weight:700;color:var(--cor-texto-secundario);text-transform:uppercase;letter-spacing:0.5px;">
                    Categorias <span style="font-weight:400;text-transform:none;">(selecione uma ou mais)</span>
                </span>
                <div style="border:1px solid var(--cor-tinte-borda);border-radius:10px;padding:8px 10px;max-height:130px;overflow-y:auto;
                            background:var(--cor-fundo-campo,var(--cor-fundo-card));display:flex;flex-direction:column;gap:2px;">
                    ${catChecksHtml}
                </div>
            </div>

            <div class="er-field-wrap">
                <input id="erData" type="date" placeholder=" " value="${ef.dataEvento || ''}">
                <label for="erData">Data</label>
            </div>

            <p id="erMsgErro" style="color:var(--red-700);font-size:0.9rem;margin:0;display:none;"></p>

            <div style="display:flex;gap:12px;">
                <button id="erBtnCancelar"
                    style="flex:1;height:52px;background:transparent;color:var(--cor-principal);border:2px solid var(--cor-principal);
                           border-radius:10px;font-size:1rem;cursor:pointer;">
                    Cancelar
                </button>
                <button id="erBtnSalvar"
                    style="flex:1;height:52px;background:var(--cor-principal);color:var(--cor-texto-claro);border:none;
                           border-radius:10px;font-size:1rem;cursor:pointer;">
                    Salvar
                </button>
            </div>
        </div>
    `;

    modal.addEventListener('click', e => { if (e.target === modal) modal.remove(); });
    modal.querySelector('#erBtnCancelar').addEventListener('click', () => modal.remove());

    modal.querySelector('#erBtnSalvar').addEventListener('click', async () => {
        const titulo    = modal.querySelector('#erTitulo').value.trim();
        const descricao = modal.querySelector('#erDescricao').value.trim() || 'Nenhuma descrição fornecida';
        const tipo      = modal.querySelector('#erTipo').value;
        const valor     = Number(modal.querySelector('#erValor').value);
        const movimento = modal.querySelector('#erMovimento').value;
        const parcelas  = Number(modal.querySelector('#erParcelas').value) || 1;
        const data      = modal.querySelector('#erData').value;
        const msgErro   = modal.querySelector('#erMsgErro');
        const btn       = modal.querySelector('#erBtnSalvar');

        // Lê instituições e categorias selecionadas
        const instIds = Array.from(modal.querySelectorAll('.er-inst-check:checked')).map(i => Number(i.value));
        const catIds  = Array.from(modal.querySelectorAll('.er-cat-check:checked')).map(i => Number(i.value));

        if (!titulo)                    { msgErro.textContent = 'Título obrigatório.';   msgErro.style.display = ''; return; }
        if (valor <= 0 || isNaN(valor)) { msgErro.textContent = 'Valor inválido.';        msgErro.style.display = ''; return; }
        if (!data)                      { msgErro.textContent = 'Data obrigatória.';      msgErro.style.display = ''; return; }
        if (instIds.length === 0)       { msgErro.textContent = 'Selecione ao menos uma instituição.'; msgErro.style.display = ''; return; }
        msgErro.style.display = 'none';

        btn.disabled = true;
        btn.textContent = 'Salvando...';

        const payload = {
            financeiro:  { usuario_id: userId, tipo, valor, descricao, dataEvento: data },
            instituicao: instIds.map(id => ({ instituicaoUsuario_id: id, tipoMovimento: movimento, valor, parcelas })),
            detalhe:     { categoriaUsuario_id: catIds, tituloGasto: titulo }
        };

        try {
            const res = await MainAPI.editarRegistro(ef.id, payload);
            if (res.ok) {
                modal.remove();
                // Atualiza apenas o card editado, sem recarregar a página inteira
                await atualizarCardRegistro(ef.id, userId);
            } else {
                let detalhe = `HTTP ${res.status}`;
                try { const corpo = await res.json(); detalhe = corpo.message || JSON.stringify(corpo); } catch (_) {}
                msgErro.textContent = `Erro ao salvar: ${detalhe}`;
                msgErro.style.display = '';
                btn.disabled = false;
                btn.textContent = 'Salvar';
            }
        } catch (e) {
            msgErro.textContent = 'Erro de conexão.';
            msgErro.style.display = '';
            btn.disabled = false;
            btn.textContent = 'Salvar';
        }
    });

    document.body.appendChild(modal);
}

// ── CONFIRMAR REMOÇÃO ────────────────────────────────────────────────────────
function confirmarRemocaoRegistro(registro) {
    let popup = document.getElementById('popupConfirmarRemocao');
    if (!popup) {
        popup = document.createElement('div');
        popup.id = 'popupConfirmarRemocao';
        popup.style.cssText = `
            position:fixed;inset:0;background:rgba(0,0,0,0.5);
            display:flex;align-items:center;justify-content:center;z-index:9999;
        `;
        popup.innerHTML = `
            <div style="background:var(--cor-fundo-card);border-radius:20px;padding:32px;width:min(380px,90vw);
                        color:var(--cor-texto-principal);
                        display:flex;flex-direction:column;gap:20px;box-shadow:0 8px 32px var(--sombra-caixa);
                        align-items:center;text-align:center;">
                <i class='bx bx-error-circle' style="font-size:3rem;color:var(--red-700);"></i>
                <div>
                    <p style="font-size:1.1rem;font-weight:600;color:var(--cor-texto-principal);margin:0 0 6px;">Remover registro?</p>
                    <p id="popupRemocaoNome" style="font-size:0.95rem;color:var(--cor-texto-secundario);margin:0;"></p>
                </div>
                <p style="font-size:0.85rem;color:var(--cor-texto-secundario);margin:0;">Esta ação não pode ser desfeita.</p>
                <div style="display:flex;gap:12px;width:100%;">
                    <button onclick="document.getElementById('popupConfirmarRemocao').style.display='none'"
                        style="flex:1;height:48px;background:transparent;color:var(--cor-principal);border:2px solid var(--cor-principal);
                               border-radius:10px;font-size:1rem;cursor:pointer;transition:background 0.2s;">
                        Cancelar
                    </button>
                    <button id="popupBtnConfirmar"
                        style="flex:1;height:48px;background:var(--red-700);color:var(--cor-texto-claro);border:none;border-radius:10px;
                               font-size:1rem;cursor:pointer;transition:background 0.2s;">
                        Remover
                    </button>
                </div>
            </div>
        `;

        // Fecha ao clicar fora
        popup.addEventListener('click', e => {
            if (e.target === popup) popup.style.display = 'none';
        });

        popup.querySelector('#popupBtnConfirmar').addEventListener('mouseover', e => e.target.style.background = 'var(--red-800)');
        popup.querySelector('#popupBtnConfirmar').addEventListener('mouseout', e => e.target.style.background = 'var(--red-700)');

        document.body.appendChild(popup);
    }

    popup.querySelector('#popupRemocaoNome').textContent = registro.titulo ? `"${registro.titulo}"` : '';
    popup.dataset.registroId = registro.id;

    // Botão Confirmar — preparado para integração
    popup.querySelector('#popupBtnConfirmar').onclick = async () => {
        const btn = popup.querySelector('#popupBtnConfirmar');
        btn.disabled = true;
        btn.textContent = 'Removendo...';
        try {
            const res = await MainAPI.deletarRegistro(popup.dataset.registroId);
            if (res.ok) {
                popup.style.display = 'none';
                carregarRegistros();
            } else {
                btn.disabled = false;
                btn.textContent = 'Remover';
            }
        } catch (e) {
            console.error('Erro ao remover registro:', e);
            btn.disabled = false;
            btn.textContent = 'Remover';
        }
    };

    popup.style.display = 'flex';
}

@import url('https://fonts.googleapis.com/css2?family=Open+Sans:ital,wght@0,300..800;1,300..800&display=swap');
@import "root.css";

* {
    margin: 0;
    padding: 0;
    border: 0;
    box-sizing: border-box;
    font-family: "Open Sans", sans-serif;;
}

h1 {
    color: var(--cor-titulo);
    font-size: 2.5rem;
    font-weight: 700;
    margin-bottom: 28px;
}

.adicionarTipo {
    width: 100%;
    height: 100%;
    justify-content: center;
    align-items: center;
    background: var(--cor-overlay);
}

.conteudoTipo {
    display: flex;
    background: var(--cor-fundo-card);
    color: var(--cor-texto-principal);
    padding: 20px;
    border-radius: 10px;
    width: 350px;
    align-items: center;
    justify-content: center;
    flex-direction: column;
}

.alerta {
    display: none;
    inset: 0;
    position: fixed;
    justify-content: center;
    align-items: center;
    background: var(--cor-overlay);
    z-index: 10000;
}

.alerta a {
    text-decoration: none;
}

.conteudoAlerta {
    display: flex;
    background: var(--cor-fundo-card);
    color: var(--cor-texto-principal);
    padding: 20px;
    border-radius: 10px;
    width: 350px;
    align-items: center;
    justify-content: center;
    flex-direction: column;
}

.conteudoAlerta button {
    padding: 10px;
    border-radius: 10px;
    background-color: var(--cor-principal);
    color: var(--cor-texto-claro);
    margin: 20px 0px;
}

.glaceonCorrendoDiv {
    display: flex;
    width: 100%;
    align-items: center;
    justify-content: center;
}

.containerGeral {
    display: flex;
    flex-direction: column;
    gap: 15px;
    background-color: var(--cor-fundo-pagina);
    color: var(--cor-texto-principal);
    min-height: 100vh;
}

.containerGeral button {
    padding: 10px;
    border-radius: 10px;
    background-color: var(--cor-principal);
    color: var(--cor-texto-claro);
    margin: 10px 0px;
}

.side-bar {
    padding: 20px;
    gap: 10px;
    font-weight: bolder;
    font-size: 23px;
    display: flex;
    flex-direction: column;
    background-color: var(--cor-principal);
    height: 100vh;
    position: fixed;
    overflow-x: hidden;
    transition: 0.5s;
    z-index: 1;
    color: var(--cor-texto-claro);
}

.main {
    display: flex;
    flex-direction: column;
}

#main {
    transition: margin-left .5s;
    padding: 20px;
    flex-grow: 1;
    width: auto;
}


.side-bar ul {
    flex-wrap: wrap;
    display: flex;
    flex-direction: column;
    justify-content: space-evenly;
    list-style: none;
    gap: 20px;
    width: 250px;
}

.side-bar li {
    display: flex;
    flex-direction: row;
    gap: 20px;
}

.side-bar a {
    display: flex;
    text-decoration: none;
    transition: 0.3s;
    color: var(--cor-texto-claro);
}

.side-bar a span {
    display: flex;
    align-items: center;
}

.side-bar a i {
    margin-right: 10px;
}

.containerKPIS {
    display: flex;
}

.KPI {
    border-radius: 1rem;
    padding: 1.5rem;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    margin: 20px;
    background-color: var(--cor-fundo-card);
    padding: 15px;
    box-shadow: 2px 2px 5px var(--cor-texto-secundario);
    width: 300px;
}

.kpi-label {
    font-size: 0.875rem;
    font-weight: 600;
    color: var(--cor-texto-secundario);
    text-transform: uppercase;
    margin-bottom: 0.5rem;
}

.gasto-valor {
    font-size: 1.875rem;
    font-weight: 600;
    display: block;
}

.badge-delta {
    display: inline-flex;
    align-items: center;
    padding: 0.25rem 0.6rem;
    border-radius: 9999px;
    font-size: 0.75rem;
    font-weight: 600;
    background-color: var(--red-100);
    color: var(--red-700);
    margin-top: 1rem;
}

.subtexto {
    font-size: 0.75rem;
    color: var(--slate-400);
    margin-left: 0.5rem;
}

.categoria-nome {
    font-size: 1.25rem;
    font-weight: 700;
}

.valor-destaque {
    font-size: 1.5rem;
    font-weight: 800;
    color: var(--cor-texto-alternativo);
}

.impacto-container {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    margin-top: 0.5rem;
}

.impactoKPI {
    background: var(--cor-principal);
    color: var(--cor-texto-claro);
    padding: 0.25rem 0.75rem;
    border-radius: 0.5rem;
    font-size: 0.875rem;
    font-weight: 700;
    display: inline-block;
    box-shadow: 0 2px 4px var(--sombra-card);
}

.valorKPItipo {
    font-size: 2.25rem;
    font-weight: 900;
    letter-spacing: -0.02em;
}

.containerGraficos {
    display: grid;
    grid-template-columns: 45% 45%;
    gap: 5%;
    width: 100%;
    justify-content: center;
    align-items: center;
}

#graficoDonut {
    z-index: 100;
    position: relative;
}

.glaceonFofinhaDivimg {
    margin: 0px 20px;
    overflow: visible;
    display: flex;
    width: 120px;
    border: var(--cor-principal) solid 2px;
    border-radius: 3px;
    align-items: end;
    justify-content: end;
    align-self: center;
}

.glaceonFofinhaDivimg img {
    margin-top: -25px;
    margin-bottom: -12px;
    width: 150px;
}

.containerFormulario {
    align-self: center;
    width: 40%;
    margin: 15px;
    padding: 10px;
    background-color: var(--cor-fundo-card);
    border-radius: 10px;
    box-shadow: 2px 2px 15px var(--cor-texto-secundario);
    min-height: 520px;
}

.formulario {
    display: grid;
    grid-template-columns: 50% 50%;
}

.campo {
    padding: 10px;
    margin: 10px 0px;
    position: relative;
}

.campo input {
    padding: 10px;
    border-radius: 10px;
    color: var(--cor-principal);
    transition: 0.2s;
    border: solid 1px var(--cor-principal);
    background-color: transparent;
}

.campo input:focus {
    outline: none;
    border: solid 2px var(--cor-principal);
}

.campo label {
    font-size: 15px;
    position: absolute;
    left: 15px;
    top: 22px;
    color: var(--cor-texto-secundario);
    background-color: var(--cor-fundo-card);
    padding: 0 4px;
    pointer-events: none;
    transition: 0.2s ease-in-out;
}

.campo input:focus+label,
.campo input:not(:placeholder-shown)+label {
    top: -1px;
    font-size: 12px;
    color: var(--cor-principal);
}

.campo select {
    padding: 10px;
    border-radius: 10px;
    color: var(--cor-principal);
    transition: 0.2s;
    border: solid 1px var(--cor-principal);
    background-color: transparent;
    /* Para manter a transparência do fundo */
    appearance: none;
    /* Para remover o estilo padrão do select */
    width: 100%;
    /* Garantir que o select ocupe toda a largura */
}

.campo select:focus {
    outline: none;
    border: solid 2px var(--cor-principal);
}

.campo label {
    font-size: 15px;
    position: absolute;
    left: 15px;
    top: 22px;
    color: var(--cor-texto-secundario);
    background-color: var(--cor-fundo-card);
    padding: 0 4px;
    pointer-events: none;
    transition: 0.2s ease-in-out;
}

.campo select:focus+label,
.campo select:not([value=""]):valid+label {
    top: -1px;
    font-size: 12px;
    color: var(--cor-principal);
}

.modal {
    display: none;
    position: fixed;
    inset: 0;
    background: var(--cor-overlay);
    justify-content: center;
    align-items: center;
    z-index: 1;
}

.conteudoModal {
    background: var(--cor-fundo-card);
    color: var(--cor-texto-principal);
    padding: 20px;
    border-radius: 10px;
    width: 350px;
}

.diasSemana,
.dias {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    text-align: center;
    margin-bottom: 10px;
}

.dias span {
    padding: 10px;
    cursor: pointer;
}

.dias span:hover {
    background: var(--cor-hover);
}

.diaSelecionado {
    background: var(--cor-principal);
    color: var(--cor-texto-principal);
    border-radius: 5px;
}

.gastos {
    min-height: 60px;
    margin-top: 10px;
    background: var(--cor-fundo-pagina);
    padding: 10px;
    border-radius: 5px;
}

.topo-calendario {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 10px;
}

.headerFormulario {
    display: flex;
    gap: 20px;
    border-bottom: 1px solid var(--cor-borda-divisor);
    padding-bottom: 8px;
    margin-bottom: 15px;
}

.headerFormulario .titulo {
    text-decoration: none;
    color: var(--cor-principal);
    padding: 8px 0;
    position: relative;

}

.headerFormulario .titulo p {
    margin: 0;
}

/* Linha que aparece quando ativo */
.headerFormulario .titulo.ativo::after {
    content: "";
    position: absolute;
    bottom: -8px;
    left: 0;
    width: 100%;
    height: 3px;
    background-color: var(--cor-principal);
    border-radius: 2px;
    transition: all 0.3s ease;
}

/* Hover opcional */
.headerFormulario .titulo:hover {
    opacity: 0.7;
    cursor: pointer;
}

.card {
    display: flex;
    flex-direction: column;
    background-color: var(--cor-fundo-card);
    padding: 10px;
    border-radius: 10px;
    box-shadow: 2px 2px 15px var(--cor-texto-secundario);
    align-items: center;
    justify-content: center;
}

.cabecalho {
    display: grid;
    grid-template-columns: repeat(6, 1fr);
    text-align: center;
    background-color: var(--cor-principal);
    color: var(--cor-texto-claro);
    padding: 10px;
    border-top-left-radius: 10px;
    border-top-right-radius: 10px;
}

.lista {
    overflow-y: auto;
    max-height: 83vh;
}

.registros {
    padding: 5px;
}

.cardRegistro {
    display: grid;
    grid-template-columns: 1fr 100px 1fr 1fr 1fr auto;
    gap: 16px;
    align-items: center;

    background: var(--cor-fundo-card);
    padding: 14px 18px;
    border-radius: 12px;
    margin-bottom: 10px;
    box-shadow: 0 6px 16px var(--sombra-card);
}

/* Botões de ação do card de registro */
.registroAcoes {
    display: flex;
    gap: 6px;
    align-items: center;
}

.registroInfo {
    text-align: center;
}

/* Badge de tipo (Gasto / Recebimento / Transferência) */
.reg-tipo-badge {
    display: inline-block;
    padding: 3px 10px;
    border-radius: 20px;
    font-size: 0.72rem;
    font-weight: 700;
    white-space: nowrap;
    margin-top: 4px;
}

/* Tags de instituições e categorias */
.reg-tags-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    align-items: center;
}

.reg-tag {
    display: inline-block;
    background: var(--cor-principal);
    color: var(--cor-texto-claro);
    border-radius: 20px;
    padding: 2px 10px;
    font-size: 0.75rem;
    font-weight: 600;
    white-space: nowrap;
}

.reg-tag-empty {
    font-size: 0.85rem;
    color: var(--cor-texto-secundario);
}

.reg-icon-btn {
    background: none;
    border: none;
    cursor: pointer;
    padding: 6px;
    margin: 0;
    border-radius: 8px;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.15s;
    font-size: 1.2rem;
    line-height: 1;
}

.reg-icon-btn.edit {
    color: var(--cor-acao-editar);
}

.reg-icon-btn.edit:hover {
    background: var(--cor-acao-editar-suave);
}

.reg-icon-btn.delete {
    color: var(--red-700);
}

.reg-icon-btn.delete:hover {
    background: var(--cor-acao-deletar-suave);
}

/* Campo com floating label dentro dos modais de registro */
.er-field-wrap {
    position: relative;
}

.er-field-wrap input,
.er-field-wrap select {
    height: 52px;
    width: 100%;
    border: 2px solid var(--cor-principal);
    border-radius: 10px;
    padding: 0 16px;
    font-size: 1rem;
    font-weight: 600;
    color: var(--cor-principal);
    background: transparent;
    box-sizing: border-box;
    appearance: none;
    transition: border-color 0.2s;
}

.er-field-wrap input:focus,
.er-field-wrap select:focus {
    outline: none;
    border-color: var(--cor-hover);
}

.er-field-wrap label {
    position: absolute;
    left: 14px;
    top: 18px;
    font-size: 15px;
    color: var(--cor-texto-secundario);
    background: var(--cor-fundo-card);
    padding: 0 4px;
    pointer-events: none;
    transition: 0.2s ease-in-out;
}

.er-field-wrap input:focus+label,
.er-field-wrap input:not(:placeholder-shown)+label {
    top: -1px;
    font-size: 12px;
    color: var(--cor-principal);
}

.er-field-wrap select+label {
    top: -1px;
    font-size: 12px;
    color: var(--cor-principal);
}

.ano {
    font-size: 1.8rem;
    font-weight: 700;
    margin-top: 32px;
}

.mes {
    font-size: 1.3rem;
    font-weight: 600;
    margin: 16px 0 8px;
    text-transform: capitalize;
}

.dataRegistro {
    font-weight: 700;
    font-size: 1.9rem;
    color: var(--cor-texto-alternativo);
}

.registroTitulo {
    font-size: 1.1rem;
    font-weight: 600;
    display: block;
}

.registroDescricao {
    font-size: 0.85rem;
    color: var(--cor-texto-secundario);
}

.registroValor {
    font-weight: 700;
    font-size: 1.1rem;
    color: var(--cor-texto-principal);
}

.registroTipo {
    background: var(--cor-hover);
    padding: 4px 8px;
    border-radius: 8px;
    font-size: 1.0rem;
    color: var(--cor-texto-claro);
}

.hidden {
    display: none;
}

.ano-header {
    font-size: 1.8rem;
    font-weight: 700;
    cursor: pointer;
    margin-top: 24px;

}

.mes-header {
    font-size: 1.3rem;
    font-weight: 600;
    margin: 16px 0 8px;
    cursor: pointer;
    text-transform: capitalize;

}

.ano-bloco {

    margin-top: 10px;
    margin-bottom: 10px;
    padding: 10px;
    border-radius: 10px;
    background-color: var(--cor-fundo-card);
}

.mes-bloco {
    margin-left: 16px;
    margin-top: 10px;
    margin-bottom: 10px;
    padding: 10px;
    border-radius: 10px;
    background-color: var(--cor-fundo-card);
    box-shadow: 0 6px 16px var(--sombra-card);
}

.ano-header,
.mes-header {
    display: flex;
    align-items: center;
    gap: 10px;
}

.ano-header::after,
.mes-header::after {
    content: "▶";
    font-size: 0.9rem;
    transition: transform 0.25s ease;
}

.ano-header.open::after,
.mes-header.open::after {
    transform: rotate(90deg);
}

.ano-header.open,
.mes-header.open {
    color: var(--cor-principal);
}

.botoes {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 10px;
    width: 100%;
}

#escondido {
    display: none;
}

