:root {
    --cor-principal: #367373;
    --cor-fundo-pagina: #EBF4F4;
    --cor-fundo-card: #FAFFFF;
    --cor-titulo: #004C58;
    --cor-hover: #B4D9D5;
    --cor-texto-principal: #1A1A1A;
    --cor-texto-secundario: #4A4A4A;
    --cor-texto-alternativo: #367373;
    --cor-texto-claro: #FFFFFF;
    --cor-para-destacar: #004C58;
    --sombra-card: rgba(54, 115, 115, 0.099);
    --red-700: #b91c1c;
    --red-100: #fee2e2;
    --red-800: #9b1c1c;
    --green-700: #15803d;
    --green-100: #d1fae5;
    /* Tints */
    --cor-tinte-suave: rgba(54,115,115,0.06);
    --cor-tinte-medio: rgba(54,115,115,0.10);
    --cor-tinte-borda: rgba(54,115,115,0.18);
    --cor-fundo-campo: rgba(54,115,115,0.05);
    --cor-fundo-inativo: #d4e8e8;
    --cor-borda-mascote: #00AEFF;
    --sombra-flutuante: rgba(0,0,0,0.12);
    --sombra-caixa: rgba(0,0,0,0.22);
    /* UI general */
    --cor-overlay: rgba(0,0,0,0.5);
    --cor-borda-divisor: #cccccc;
    --cor-fundo-cadastro: #5FA8A3;
    --cor-padrao-geometrico: rgba(255,255,255,0.08);
    /* Toggle / switch */
    --cor-toggle-inativo: #d1d5db;
    --cor-toggle-handle: #535353;
    /* Action colors (edit / delete) */
    --cor-acao-editar: #00BBDD;
    --cor-acao-editar-suave: rgba(0,187,221,0.12);
    --cor-acao-deletar-suave: rgba(229,62,62,0.12);
    /* Event / agenda colors */
    --cor-gasto-bg: #FF9E9E;
    --cor-gasto-texto: #A00000;
    --cor-recebimento-bg: #B7FFB6;
    --cor-recebimento-texto: #0A6000;
    --cor-transferencia-bg: #7FFFFF;
    --cor-transferencia-texto: #006C9E;
    --cor-agendamento-bg: #FFFF9E;
    --cor-agendamento-texto: #AFA900;
    /* Poupança / Empréstimo badge colors */
    --cor-poupanca-bg: #B0D4FF;
    --cor-poupanca-texto: #1E3A6E;
    --cor-emprestimo-bg: #FFE0B0;
    --cor-emprestimo-texto: #7A3800;
    /* Dark-mode variants (overridden per theme) */
}

